import axios from 'axios';

// 创建axios实例
const apiClient = axios.create({
  baseURL: process.env.VUE_APP_API_URL || 'http://localhost:8080/api',
  timeout: 10000,
  withCredentials: true,
  headers: {
    'Accept': 'application/json',
    'Content-Type': 'application/json'
  }
});

// 请求拦截器
apiClient.interceptors.request.use(
  config => {
    // 从localStorage获取token
    const userStr = localStorage.getItem('user');
    if (userStr) {
      try {
        const user = JSON.parse(userStr);
        const token = user.accessToken || user.token;
        if (token) {
          // 在请求头中添加token
          config.headers['Authorization'] = `Bearer ${token}`;
        }
      } catch (e) {
        // 解析失败时不添加token
      }
    }
    
    return config;
  },
  error => {
    return Promise.reject(error);
  }
);

// 响应拦截器
apiClient.interceptors.response.use(
  response => {
    return response.data;
  },
  error => {
    // 检查是否是禁用账户错误 (401 Unauthorized + 包含"禁用"关键词)
    const isDisabledAccount = error.response && 
      error.response.status === 401 && 
      error.response.data && 
      error.response.data.message && 
      error.response.data.message.includes('禁用');
      
    if (isDisabledAccount) {
      // 增强错误对象，添加禁用标记
      error.isDisabledAccount = true;
      error.disabledMessage = '账号已被禁用，请联系管理员';
      console.warn('账号已被禁用:', error.response.data.message);
    }
    
    // 处理其他身份验证错误
    if (error.response && error.response.status === 401 && !isDisabledAccount) {
      // 非禁用导致的401错误，清除用户信息并重定向
      localStorage.removeItem('user');
      
      // 如果不在登录页面，重定向到登录页面
      if (window.location.pathname !== '/login') {
        window.location.href = '/login?redirect=' + encodeURIComponent(window.location.pathname);
      }
    }
    
    return Promise.reject(error);
  }
);

export default apiClient;
